import{_ as b,o as f,c as k,a6 as K,gn as C,go as x,gp as P,gq as S,l1 as V,es as D,l2 as w,gt as v,l3 as A,gv as E,gw as L,gh as $,gx as T,gy as s,gz as B,gA as F,l4 as N,gB as y,gC as M,gD as R,l5 as G,gG as t,gH as H,l6 as a,l7 as g,gK as I,gL as n,gM as O,gN as q,gO as j,gP as Q,gQ as X,gR as W,gS as i,gT as J,l8 as U,l9 as z,la as Y,gV as Z,gW as ss,gX as ts,gY as ps,gZ as rs,ey as os,g_ as as,g$ as gs,h0 as ns,lb as is,h2 as ls,lc as es,h4 as ms,ld as l,le as cs,h5 as _s,h6 as hs,h7 as ds,h8 as us,lf as bs,ha as e,hb as p,hc as m,lg as c,lh as _,he as fs,li as ks,lj as Ks,lk as Cs,ll as xs,lm as Ps,ln as Ss,hm as Vs,eu as h,hp as Ds,hq as ws,hr as vs,hs as As,ht as Es,hu as Ls,hv as $s,hw as Ts,hx as Bs,hy as Fs,lo as Ns,lp as ys,lq as Ms,lr as Rs,hE as Gs,hF as Hs,hG as Is,hH as Os,hI as qs,hJ as js,hK as Qs,hL as r,hM as Xs,hN as Ws,ls as d,lt as u,lu as Js,hR as Us,lv as zs,lw as Ys,lx as Zs}from"./chunks/framework.UYVGz2W_.js";const it=JSON.parse('{"title":"TV番組制作の作成","description":"","frontmatter":{},"headers":[],"relativePath":"ja/tvshow/index.md","filePath":"ja/tvshow/index.md"}'),st={name:"ja/tvshow/index.md"};function tt(pt,o,rt,ot,at,gt){return f(),k("div",null,[...o[0]||(o[0]=[K('<h1 id="tv番組制作の作成" tabindex="-1">TV番組制作の作成 <a class="header-anchor" href="#tv番組制作の作成" aria-label="Permalink to “TV番組制作の作成”">​</a></h1><p>Kitsuでワークフローを設計し、チームメンバーを追加したので、今度は制作を作成します。</p><p>「<strong>新規制作の作成」</strong>ボタンをクリックします。</p><p><img src="'+C+'" alt="制作の作成"></p><p>制作の名前を入力し、<strong>タイプ</strong>として<strong>「テレビ番組」</strong>を選択し、制作のスタイル（2D、3D）を選択します。</p><p>次に、FPSの数、アスペクト比、解像度などの技術情報を入力します。</p><p>::: 警告 これらのデータは、お客様がアップロードしたビデオプレビューをキットが再エンコードする際に使用されます。 :::</p><p>次に、制作物の開始日と終了日を定義します。</p><p><img src="'+x+'" alt="制作物の追加"></p><p>制作ワークフローは、次のパート3から6で定義できます。</p><p>アセットタスクタイプ（3）、ショットタスクタイプ（4）、タスクステータス（5）、アセットタイプ（6）を選択する必要があります。</p><p><img src="'+P+'" alt="Add a production Pipeline"></p><p>::: ヒント <strong>制作ワークフロー</strong>を作成するには、グローバルライブラリからタスクタイプを選択します。</p><p>タスクタイプをいくつか見落としていたことに気づいた場合は、後で作成することができます。</p><p><a href="./../configure-kitsu/">Kitsuの入門ガイド</a>を参照してください。 :::</p><p>次に、ステップ7と8はオプションです。アセットまたはショットの一覧がすでにスプレッドシートにある場合は、<strong>CSVのインポート</strong>セクションを参照してください。</p><p><img src="'+S+'" alt="All done">ボタンですべてを確認します。</p><h2 id="kitsuのグローバルページの紹介" tabindex="-1">Kitsuのグローバルページの紹介 <a class="header-anchor" href="#kitsuのグローバルページの紹介" aria-label="Permalink to “Kitsuのグローバルページの紹介”">​</a></h2><p>Kitsuのグローバルアセットページへようこそ。 まずは全体を見てみましょう。</p><p><img src="'+V+'" alt="グローバルページの紹介"></p><p>ページの上部には、<strong>グローバルナビゲーション</strong>があります。これは、すべての制作ページで表示されます。</p><p><strong>左から右へ：</strong></p><h3 id="メインメニュー" tabindex="-1">メインメニュー <a class="header-anchor" href="#メインメニュー" aria-label="Permalink to “メインメニュー”">​</a></h3><p>左上のボタンをクリックすると、Kitsu<img src="'+D+'" alt="メインメニューボタン">（またはお客様のスタジオロゴ）が表示され、メインメニューが開きます。</p><p>メインメニューでは、割り当てられたタスク、制作、グローバルおよびチームスケジュール、ワークフローのカスタマイズページ、およびKitsuの設定に直接アクセスできます。</p><p>::: 詳細 メインメニューの詳細 <strong>ワークスペース</strong></p><ul><li><strong>マイタスク：</strong> 割り当てられたタスク。</li><li><strong>マイチェック：</strong> 部署に応じて、ステータスが<strong>フィードバックリクエスト</strong>となっているすべてのタスク。</li><li><strong>マイプロダクション：</strong> プロダクション選択ページに戻る。</li></ul><p><strong>スタジオ</strong></p><ul><li><strong>プロダクション：</strong> すべてのプロダクション（オープンまたはクローズ）の詳細リスト。</li><li><strong>メンバー：</strong> スタジオ内のすべてのメンバー（アクティブまたは非アクティブ）のリスト。</li><li><strong>タイムシート：</strong> チームが制作ごとに記録した作業時間の明細。</li><li><strong>メインスケジュール：</strong> すべての制作を1つのスケジュールに表示。</li><li><strong>チームスケジュール：</strong> スタジオ内のすべてのスタッフのスケジュールとタスクを表示。</li><li><strong>すべてのタスク：</strong> すべての制作のすべてのタスクに一括してアクセス。</li><li><strong>ニュースフィード：</strong> 最新情報を入手。</li><li><strong>エンティティ検索：</strong> すべての制作にわたって、任意のアセットまたはショットを検索。</li></ul><p><strong>ADMIN</strong></p><ul><li><strong>Departments:</strong> 部署を作成および編集。</li><li><strong>Task Types:</strong> タスクの種類を作成および編集。</li><li><strong>Asset Types:</strong> アセットの種類を作成および編集。</li><li><strong>Custom Actions:</strong> カスタムアクションを作成および編集。</li><li><strong>Automation:</strong> 自動化を作成および編集。</li><li><strong>3D Backgrounds:</strong> HDR背景を追加。</li><li><strong>Bots:</strong> ボットを作成および編集。</li><li><strong>設定</strong>：スタジオの設定を行います。</li><li><strong>ログ</strong></li></ul><p>::: 警告 権限 表示 WORKSPACEセクションは、アーティストには表示されない「My Checks」を除くすべての権限に対して有効になっています。</p><p>アーティスト（およびそれ以上の権限を持つユーザー）は、自身の<strong>タイムシート</strong>も確認でき、<strong>エンティティ検索</strong>にもアクセスできます。 :::</p><h3 id="ナビゲーション" tabindex="-1">ナビゲーション <a class="header-anchor" href="#ナビゲーション" aria-label="Permalink to “ナビゲーション”">​</a></h3><p>メインメニューアイコンの右側にナビゲーションドロップダウンメニューが表示されます。</p><p><img src="'+w+'" alt="グローバルページの表示"></p><p>異なる制作物の中から選択することができます。現在の制作物の名称と現在のページは常に表示されます。</p><p>複数の制作物がある場合は、ドロップダウンメニューを使用して、制作物間を移動することができます。制作物を選択すると、次のドロップダウンメニューで、その制作物の異なるページ間を移動することができます。</p><p>::: 詳細 ナビゲーション 詳細 最初のセクションは、タスクの追跡に関するものです。</p><ul><li><strong>アセット</strong></li><li><strong>ショット</strong></li><li><strong>シーケンス</strong></li><li><strong>エピソード</strong></li><li><strong>編集</strong>（特定のタスクを作成した場合）</li></ul><p>2番目のセクションは、制作側により重点を置いたものです。</p><ul><li><strong>コンセプト</strong></li><li><strong>ブレイクダウン</strong></li><li><strong>プレイリスト</strong></li><li><strong>ニュースフィード</strong></li></ul><p>3番目のセクションは、統計に関するものです。</p><ul><li><strong>シーケンス統計</strong></li><li><strong>エピソード統計</strong></li><li><strong>アセットタイプ統計</strong></li></ul><p>第4セクションはチーム管理に関連するものです。</p><ul><li><strong>スケジュール</strong></li><li><strong>ノルマ</strong></li><li><strong>チーム</strong></li></ul><p>第5セクションは制作の設定に関するものです。</p><ul><li><strong>設定</strong></li></ul><p>::: ヒント アセットページから開始しますが、制作ホームページを他のエンティティに変更することができます（設定ページを参照）。 :::</p><p>::: 警告 <strong>エピソード</strong>などの追加のナビゲーションレベルが必要ないことに気づいた場合は、制作タイプを<strong>ショート</strong>に変更する必要があります。 :::</p><h3 id="グローバル検索、ニュース、通知、およびドキュメント" tabindex="-1">グローバル検索、ニュース、通知、およびドキュメント <a class="header-anchor" href="#グローバル検索、ニュース、通知、およびドキュメント" aria-label="Permalink to “グローバル検索、ニュース、通知、およびドキュメント”">​</a></h3><p>ナビゲーションドロップダウンメニューの右側にグローバル検索があります。このクイックアクセス機能では、最初の4件の結果が表示されます。さらに多くの結果やフィルタリングオプションが必要な場合は、メインメニューの「<strong>エンティティ検索</strong>」ページにアクセスしてください。</p><p>次のアイコン <img src="'+v+'" alt="News"> は、ニュースとフィードバックページへの直接リンクです。ここでは、すべての新機能（アニメーションGIF付き）を表示したり、Kitsuに追加してほしい機能の提案を送信したりすることができます。</p><p>次に、ベルのアイコン <img src="'+A+'" alt="通知"> は、通知（割り当て、コメント、タグ）を表示します。 未読の通知の数は、ベルのアイコンに表示されます。 さまざまなフィルター機能により、更新情報を把握し、必要なときに重要な更新情報を再確認することができます。 通知を既読または未読として簡単にマークしたり、ウォッチ/非ウォッチで素早くフィルターをかけたりして、最も重要なものに焦点を当て、フィードを整理することができます。</p><p>アバターの直前のアイコンは、ドキュメントボタンです！<a href="../img/getting-started/documentation_button.png">ドキュメントボタン</a>は、まさに今あなたが読んでいるボタンです！</p><h3 id="個人設定" tabindex="-1">個人設定 <a class="header-anchor" href="#個人設定" aria-label="Permalink to “個人設定”">​</a></h3><p>アバターをクリックすると、プロフィールメニュー（プロフィール、カラーテーマ、ビデオチュートリアルなど）を開くことができます。</p><p><img src="'+E+'" alt="プロフィール拡大"></p><h2 id="タスクリスト" tabindex="-1">タスクリスト <a class="header-anchor" href="#タスクリスト" aria-label="Permalink to “タスクリスト”">​</a></h2><h3 id="エンティティスプレッドシート" tabindex="-1">エンティティスプレッドシート <a class="header-anchor" href="#エンティティスプレッドシート" aria-label="Permalink to “エンティティスプレッドシート”">​</a></h3><p>画面の2番目の部分は、すべてのエンティティ（アセット、ショット、シーケンス、編集）に共通です。これはグローバルなタスクリストです。</p><p>ここでは、各タスクのステータス、割り当て、優先度、その他の詳細を確認できます。</p><p>::: ヒント スプレッドシートの最初の行と列のヘッダーは、ページをスクロールしても常にページの上部に表示されます。</p><p>また、他の列を常に表示しておくために固定することもできます。 :::</p><h3 id="フィルター" tabindex="-1">フィルター <a class="header-anchor" href="#フィルター" aria-label="Permalink to “フィルター”">​</a></h3><p>左側の最初の要素はフィルターボックスです。 シーケンスやアセットタイプなど、簡単なフィルタリングを行う場合は、任意の文字列を入力することができます。</p><p>より高度なフィルタリングを行う場合は、フィルタービルダーボタンを使用してください。</p><p><img src="'+L+'" alt="フィルタービルダー"></p><p>すべてのフィルターを保存し、ページとして使用することができます。</p><h3 id="表示の簡素化" tabindex="-1">表示の簡素化 <a class="header-anchor" href="#表示の簡素化" aria-label="Permalink to “表示の簡素化”">​</a></h3><p>画面の右側には、いくつかのボタン（左から右へ）があり、アサインメントの表示/非表示、追加カラムの表示/非表示、サムネイルの拡大/縮小を行うことができます。</p><p><img src="'+$+'" alt="表示/非表示オプション"></p><h3 id="インポート-エクスポート" tabindex="-1">インポート / エクスポート <a class="header-anchor" href="#インポート-エクスポート" aria-label="Permalink to “インポート / エクスポート”">​</a></h3><p>ここでは、サムネイルの一括インポート <img src="'+T+'" alt="サムネイルの一括インポート"> を行い、最後にインポート <img src="'+s+'" alt="インポートボタン"> またはエクスポート <img src="'+B+'" alt="エクスポートボタン"> を行います。</p><h3 id="メタデータカラム" tabindex="-1">メタデータカラム <a class="header-anchor" href="#メタデータカラム" aria-label="Permalink to “メタデータカラム”">​</a></h3><p>以下に、カラムの名前があります。<strong>Name</strong>の隣にある(+)をクリックすると、新しいメタデータカラムを作成できます。次に、タスクタイプカラムの名前があります。</p><h3 id="ビューのカスタマイズ" tabindex="-1">ビューのカスタマイズ <a class="header-anchor" href="#ビューのカスタマイズ" aria-label="Permalink to “ビューのカスタマイズ”">​</a></h3><p>画面の一番右側、スクロールバーの隣に、追加の列（タスクタイプ以外のすべて）を非表示または表示するオプションがあります。</p><p><img src="'+F+'" alt="テキスト列の表示/非表示">。</p><h3 id="ビューの要約" tabindex="-1">ビューの要約 <a class="header-anchor" href="#ビューの要約" aria-label="Permalink to “ビューの要約”">​</a></h3><p>画面の一番下にある最後の部分（4）は、表示されているページの要約です。つまり、ページをフィルタリングすると、要約も更新されます。</p><p>要素（アセットまたはショット）の数、見積もり日数の合計、およびすでに費やした日数の合計を確認できます。</p><p><img src="'+N+'" alt="表示要約"></p><h2 id="アセットの作成" tabindex="-1">アセットの作成 <a class="header-anchor" href="#アセットの作成" aria-label="Permalink to “アセットの作成”">​</a></h2><h3 id="最初のアセットの作成" tabindex="-1">最初のアセットの作成 <a class="header-anchor" href="#最初のアセットの作成" aria-label="Permalink to “最初のアセットの作成”">​</a></h3><p>制作物を制作し、Kitsuインターフェースの概要を理解したので、いよいよ最初の制作物を作成します。</p><p>アセットページで、<strong>[アセットを追加]</strong>をクリックします。</p><p><img src="'+y+'" alt="アセットページ初回"></p><p>::: 警告 アセットを作成すると、タスクワークフローが適用され、<strong>すべてのタスクが同時に作成されます</strong>。 :::</p><p>ポップアップウィンドウが開きます。</p><ul><li><strong>アセットタイプ</strong>を選択するよう求められます（1）。新しいアセットタイプを追加していない場合、Kitsuは「キャラクター」、「環境」、「FX」、「小道具」などの例を提供します。まずはキャラクターから始めましょう。</li></ul><p>::: ヒント アセットタイプのリストとタスクパイプラインはカスタマイズすることもできます。 <a href="./../configure-kitsu/#specific-asset-types-workflow">アセットタイプのワークフローを参照</a> :::</p><p>このアセットをエピソードにリンクし（Kitsuではデフォルトで編集や削除ができない<strong>Main Pack</strong>が提供されます）、最初のエピソードとして<strong>E01</strong>を選択して作業を開始します。 E01の名前を変更したり削除することもできます。</p><p>(3) <strong>名前</strong>を付け、アーティストが何をすべきか理解し、アセットを素早く識別できるように説明を入力します。</p><p>複数のアセットを作成する場合は、<strong>[確認して続行]</strong>をクリックします。</p><p><img src="'+M+'" alt="アセットの作成"></p><p>アセットの種類を変更して、アセットの追加を続行できます。</p><p>::: ヒント 「確認して続行」をクリックするたびに、新しく作成されたアセットがバックグラウンドに表示されます。 :::</p><p>最後のアセットを追加したら、「確認」をクリックします。これによりアセットが作成され、ウィンドウが閉じます。</p><p>::: ヒント 「確認して続行」をクリックした後、追加するアセットがないことに気づいた場合は、「閉じる」をクリックするとウィンドウがキャンセルされます。 :::</p><p><img src="'+R+'" alt="グローバルアセットページ"></p><p>また、アセットのワークフロー用に選択されたタスクも同時に作成されます。</p><p>さらに<strong>アセット</strong>を追加する必要がある場合は、<strong>+ アセットの作成</strong>ボタンをクリックします。</p><p>::: 詳細 CSVスプレッドシートファイルからアセットを作成 アセットのリストがすでにスプレッドシートファイルに用意されているかもしれません。 Kitsuでは、インポートする方法が2つあります。1つ目は、<code>.csv</code>ファイルをインポートし、データを直接Kitsuにコピー＆ペーストする方法です。</p><p>まず、スプレッドシートを<code>.csv</code>ファイルとして保存します。</p><p>次に、Kitsuのアセットページに戻り、<strong>インポート</strong>アイコンをクリックします。 <img src="'+s+'" alt="インポートアイコン"></p><p>ポップアップウィンドウの<strong>「CSVからデータをインポート」</strong>が開きます。<strong>「参照」</strong>をクリックして、<code>.csv</code>ファイルを選択します。</p><p><img src="'+G+'" alt="CSVファイルのインポート"></p><p>結果を確認するには、<strong>[プレビュー]</strong>ボタンをクリックします。</p><p>データのプレビューで列名を確認し、調整することができます。</p><p>注意：<strong>[エピソード]</strong>列は、<strong>[テレビ番組]</strong>制作の場合のみ必須です。</p><p>すべてが正しいことを確認したら、<strong>[確認]</strong>ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、すべてのアセットがKitsuにインポートされ、設定に従ってタスクが作成されました。</p><p><img src="'+t+'" alt="インポート結果"> :::</p><p>::: 詳細 スプレッドシートファイルをコピー/ペーストしてアセットを作成</p><p>スプレッドシートを開き、データを選択してコピーします。</p><p><img src="'+H+'" alt="インポートコピーデータ"></p><p>次に、Kitsuのアセットページに戻り、<strong>インポート</strong>アイコンをクリックします。 <img src="'+s+'" alt="インポートアイコン"></p><p>ポップアップウィンドウの<strong>「CSVからデータをインポート」</strong>が開きます。<strong>「CSVデータを貼り付け」</strong>タブをクリックします。</p><p><img src="'+a+'" alt="インポートデータコピーペーストタブ"></p><p>以前に選択したデータを貼り付け、<strong>[プレビュー]</strong>ボタンで結果を確認できます。</p><p><img src="'+g+'" alt="データのコピー＆ペースト"></p><p>データのプレビューで列名を確認し、調整できます。</p><p>注意：<strong>[エピソード]</strong>列は、<strong>[テレビ番組]</strong>制作の場合のみ必須です。</p><p>すべてが正しく入力されたら、<strong>Confirm</strong>ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、すべてのアセットがKitsuにインポートされ、設定に従ってタスクが作成されました。</p><p><img src="'+t+'" alt="インポート結果"> :::</p><h3 id="アセットの詳細の表示" tabindex="-1">アセットの詳細の表示 <a class="header-anchor" href="#アセットの詳細の表示" aria-label="Permalink to “アセットの詳細の表示”">​</a></h3><p>アセットの詳細を表示するには、その名前をクリックします。</p><p><img src="'+I+'" alt="アセットの詳細"></p><p>新しいページが開き、右側にタスク、割り当て、ステータスの更新の一覧が表示されます。</p><p><img src="'+n+'" alt="アセットの詳細ページ"></p><p>各タスクのステータスをクリックすると、コメントパネルが開き、コメントの履歴や異なるバージョンのコメントを見ることができます。</p><p><img src="'+O+'" alt="アセット詳細ページ"></p><p>また、以下の情報にもアクセスできます。</p><ul><li><strong>キャスティング</strong></li></ul><p><img src="'+q+'" alt="アセット詳細ページのキャスティング"></p><ul><li>このアセットにリンクされた<strong>コンセプト</strong></li></ul><p><img src="'+j+'" alt="Asset Detail Concepts"></p><ul><li>タスクタイプページのデータを事前に記入している場合は、<strong>スケジュール</strong>が利用可能です。データがすでに記入されている場合は、ここで直接修正することができます。</li></ul><p><img src="'+Q+'" alt="Asset Detail Schedule"></p><ul><li>さまざまなタスクタイプでアップロードされた<strong>プレビューファイル</strong></li></ul><p><img src="'+X+'" alt="Asset Detail Preview Files"></p><ul><li>そして、このアセットのタスクでタイムシートが記入されている場合の<strong>タイムログ</strong>。</li></ul><p><img src="'+W+'" alt="Asset Detail Timelog"></p><h2 id="アセットの更新" tabindex="-1">アセットの更新 <a class="header-anchor" href="#アセットの更新" aria-label="Permalink to “アセットの更新”">​</a></h2><p>アセットはいつでも更新でき、名前やアセットタイプを変更したり、説明文を修正したり、グローバルページに追加したカスタム情報を追加したりすることができます。</p><p>アセットを編集するには、アセットページに移動し、変更したいアセットの上にカーソルを移動させて、行の右側にある<strong>[編集]</strong>ボタンをクリックします！<a href="../img/getting-started/edit_button.png">編集ボタン</a> (1)</p><p><img src="'+i+'" alt="アセットの編集"></p><p>アセットのメインページで詳細を表示するには、最初の文字 (2) をクリックすると、詳細が記載されたポップアップが開きます。</p><p>アセットを削除するには、FAQ: アセットの削除方法を参照してください。</p><p>::: 詳細 CSV インポートによるアセットの更新 CSV インポートを使用すると、データをすばやく更新することができます。</p><p>アセットの<strong>タイプ</strong>、<strong>割り当て</strong>、タスクの<strong>ステータス</strong>を更新したり、<strong>コメント</strong>を追加したりすることができます。</p><p><strong>既存のデータを更新する</strong>オプションをオンにする必要があります。すると、更新される行が青くハイライトされます。</p><p><img src="'+J+'" alt="データのインポート データのコピー＆ペースト"> ::::</p><p>:::: 詳細 スプレッドシートファイルのコピー＆ペーストによるアセットの更新</p><p>スプレッドシートを開き、データを選択してコピーします。</p><p><img src="'+U+'" alt="データのインポート データのコピー"></p><p>次に、Kitsuのアセットページに戻り、<strong>インポート</strong>アイコンをクリックします！<a href="../img/getting-started/import.png">インポートアイコン</a>。</p><p>ポップアップウィンドウ「<strong>CSVからのインポート</strong>」が開きます。「<strong>CSVデータの貼り付け</strong>」タブをクリックします。</p><p><img src="'+a+'" alt="インポートデータのコピー＆ペーストタブ"></p><p>以前に選択したデータを貼り付け、<strong>[プレビュー]</strong>ボタンで結果を確認できます。</p><p><img src="'+g+'" alt="データのインポートとコピー＆ペースト"></p><p>データのプレビューで列の名前を確認し、調整できます。</p><p>オプションの<strong>[既存のデータを更新]</strong>をオンにする必要があります。すると、更新される行が青くハイライトされます。</p><p><img src="'+z+'" alt="データのインポート データのコピー＆ペースト"></p><p>これで、すべての資産をKitsuにインポートし、設定に従ってタスクを更新しました。</p><p><img src="'+t+'" alt="インポート結果"> ::::</p><h2 id="アセット作成後にタスクを追加する" tabindex="-1">アセット作成後にタスクを追加する <a class="header-anchor" href="#アセット作成後にタスクを追加する" aria-label="Permalink to “アセット作成後にタスクを追加する”">​</a></h2><p>アセットを作成した後で、タスクが不足していることに気づいた場合でも、追加することができます。</p><p>まず、不足しているタスクタイプが設定ページのタスクタイプタブに追加されていることを確認してください（そうでなければ、<a href="./../configure-kitsu/">Kitsuの使い方</a>を参照）。</p><p>次に、アセットページに戻り、<strong>+ タスクを追加</strong>をクリックします。</p><h2 id="コンセプトの作成" tabindex="-1">コンセプトの作成 <a class="header-anchor" href="#コンセプトの作成" aria-label="Permalink to “コンセプトの作成”">​</a></h2><h3 id="コンセプトのアップロード" tabindex="-1">コンセプトのアップロード <a class="header-anchor" href="#コンセプトのアップロード" aria-label="Permalink to “コンセプトのアップロード”">​</a></h3><p><strong>コンセプト</strong>を作成するには、ナビゲーションメニューを使用して<strong>コンセプト</strong>ページに移動します。</p><p><img src="'+Y+'" alt="コンセプトメニュー"></p><p>コンセプトをアップロードするには、<strong>コンセプトへの新しい参照を追加</strong>ボタンをクリックします。</p><p>同時に1つまたは複数のコンセプトをアップロードできます。</p><p><img src="'+Z+'" alt="コンセプトの空ページ"></p><p>プレビューをアップロードすると、コンセプトページは次のようになります。</p><p><img src="'+ss+'" alt="コンセプトの記入済みページ"></p><p>コンセプトとやりとりするには2つの方法があります。1つ目は、画像をクリックして拡大表示する方法です。2つ目は、ステータスの部分をクリックして右側の<strong>コメントパネル</strong>を開く方法です。</p><p>コメントパネルでは、2つのオプションがあります。コンセプトを既存のアセットにリンクするか、削除するかです。また、アセットにコメントを追加したり、ステータスを変更することもできます。</p><p><strong>コンセプト</strong>ごとに1つのバージョンを持つことが基本です。承認されていない場合は、同じコンセプトの複数のバージョンを作成しないよう、新しいコンセプトをアップロードする必要があります。</p><p>1つのコンセプトは1つのタスクです。</p><p><img src="'+ts+'" alt="コンセプトオプション"></p><h3 id="コンセプトとアセットのリンク" tabindex="-1">コンセプトとアセットのリンク <a class="header-anchor" href="#コンセプトとアセットのリンク" aria-label="Permalink to “コンセプトとアセットのリンク”">​</a></h3><p>コンセプトをアップロードすると、アセットにリンクすることができます。</p><p>アセットのステータス部分にリンクが表示されます。</p><p>コンセプトのステータス部分をクリックすると、右側にコメントパネルが開きます。</p><p><img src="'+ps+'" alt="コンセプトコメントパネル"></p><p>コメントパネルの上部には、コンセプトをアセットにリンクするか、コンセプトを削除するかの2つのオプションがあります。</p><p>アセットをリンクするには、[リンク] ボタン <img src="'+rs+'" alt="リンクボタン"> をクリックします。</p><p>Kitsu は、アップロードしたコンセプトにリンク可能なすべての <strong>アセット</strong> を表示します。</p><p>Kitsu は、リンクされたアセットをコメントパネルの上部にリスト表示します。現時点では、リンクはありません。</p><p><img src="'+os+'" alt="コンセプトリンク"></p><p>アセットをリンクするには、それをクリックします。リンクされたアセットの名前は、コンセプトのプレビューの下に画面の上部に表示されます。</p><p><img src="'+as+'" alt="コンセプトアセットリンク"></p><p>コンセプトがアセットにリンクされると、アセットの詳細ページで確認できます。</p><p>アセットページに戻り、コンセプトを確認したいアセット名をクリックします。</p><p><img src="'+n+'" alt="アセット詳細ページ"></p><p>デフォルトでは、キャスティングの詳細が画面の2番目の部分に表示されます。 ドロップダウンメニューを使用してコンセプトを選択します。</p><p><img src="'+gs+'" alt="アセット詳細コンセプト"></p><p>コンセプトセクションに入ると、このアセット用に作成されたすべてのコンセプトが表示されます。ステータスごとにフィルタリングすることができます。</p><p><img src="'+ns+'" alt="アセット詳細コンセプトリスト"></p><h2 id="ショットの作成" tabindex="-1">ショットの作成 <a class="header-anchor" href="#ショットの作成" aria-label="Permalink to “ショットの作成”">​</a></h2><h3 id="最初のショットの作成" tabindex="-1">最初のショットの作成 <a class="header-anchor" href="#最初のショットの作成" aria-label="Permalink to “最初のショットの作成”">​</a></h3><p>制作用の<strong>ショット</strong>を作成する時が来ました。</p><p>::: 警告 <strong>ショット</strong>は<strong>シーケンス</strong>にリンクされ、シーケンスはまたキットゥの<strong>エピソード</strong>にもリンクされます。 つまり、エピソードを作成し、次にシーケンスを作成し、このシーケンスにショットを追加する必要があります。 :::</p><p>ドロップダウンメニューを使用して<strong>ショット</strong>ページに移動し、<strong>ショット</strong>をクリックします。</p><p><img src="'+is+'" alt="ドロップダウンメニューショット"></p><p>ショット作成を開始するには、<strong>ショットを追加</strong>ボタンをクリックします。</p><p><img src="'+ls+'" alt="最初のショット追加"></p><p>::: 警告 ショットを作成すると、設計したタスクワークフローが適用され、すべてのタスクがショットと同時に作成されます。</p><p><a href="./../configure-kitsu/">Kitsuの使い方</a>を参照してください。 :::</p><p>ショットの作成用に新しいポップアップが開きます。 これで、エピソード、シーケンス、ショットを作成できます。</p><p>Kitsuは最初のエピソードとして例として<strong>E01</strong>を提供しています。それを選択し、最初のシーケンス、例えばsq01を追加し、 <strong>追加</strong>をクリックします。</p><p>これでシーケンスが作成されたことが確認できます。このシーケンスにショットを追加するには、シーケンスを選択し、ショットを作成する必要があります。</p><p>例えば、ショットの列に「sh0010」と入力し、<strong>「追加」</strong>をクリックします。 ショットのパディングを定義することもできます。</p><p>::: ヒント ショットを10個ずつSH0010、SH0020、SH0030などのように名前を付けたい場合は、「ショットのパディング」を10に設定します :::</p><p><img src="'+es+'" alt="Manage Shots"></p><p>新しいショットがシーケンスごとにリスト化され、リンクされているのがお分かりいただけると思います。また、棚はエピソードにリンクされています。 これで、最初のエピソードの最初のシーケンスの最初のショットが作成されました。</p><p>それでは、1つ以上のショットを追加してみましょう！ご覧の通り、ボックスにはすでに名前のコードが含まれていますが、 コードがすでに含まれていますが、インクリメントされているので、<strong>追加</strong>をクリックして、 さらにショットを作成する必要があります。</p><p><img src="'+ms+'" alt="ショットの追加"></p><p>さらにシーケンスを追加するには、左側部分に移動し、新しいシーケンスの名前を入力して、<strong>追加</strong>をクリックします。 2番目のシーケンスが選択され、ショットを追加できるようになります。</p><p>同じ手順でさらにエピソードを追加することができます。</p><p>新しいエピソードを作成すると、順次選択され作成されます。 シーケンスが作成されると、選択され、このシーケンスにショットを作成することができます。</p><p>::: ヒント ショットがシーケンス上で誤った位置に配置されている場合は、ショットを編集する必要があります ！<a href="../img/getting-started/edit_button.png">編集ボタン</a>をクリックし、 シーケンスを変更します。</p><p>ただし、ショットのエピソードを変更することはできません。</p><p><img src="'+l+'" alt="ショットの編集 シーケンスの変更"></p><p><img src="'+cs+'" alt="シーケンスの変更"> :::</p><p>ショットを削除するには、FAQを参照してください。ショットの削除方法</p><p>シーケンスを削除するには、FAQを参照してください。シーケンスの削除方法</p><h2 id="edlファイルからショットを作成" tabindex="-1">EDLファイルからショットを作成 <a class="header-anchor" href="#edlファイルからショットを作成" aria-label="Permalink to “EDLファイルからショットを作成”">​</a></h2><p>すでに<strong>EDL</strong>ファイルにショットリストが用意されているかもしれません。Kitsuでは、<strong>EDL</strong>ファイルを直接インポートして、シーケンス、ショット、フレーム数、フレームイン/アウトを作成することができます。</p><p><strong>グローバルショットページ</strong>には、<strong>[インポートEDL]</strong>ボタンがあります。</p><p><img src="'+_s+'" alt="インポートEDLボタン"></p><p>ポップアップで、編集時に使用するビデオファイルの命名規則を選択できます。</p><p><img src="'+hs+'" alt="インポートEDLメニュー"></p><p>これは、プロジェクト_シーケンス_ショット.拡張子という名前で編集上のビデオクリップが命名されていることを意味します。</p><p>LGC制作のEDLの例を以下に示します。</p><p><img src="'+ds+'" alt="EDLの例"></p><p>動画ファイルの名前はLGC_100-000.movとなっており、LGCが制作名、100がシーケンス名、000がショット名であることを意味しています。</p><p>命名規則を設定したら、EDLファイルをインポートできます。</p><p>次に、<strong>[Upload EDL]</strong>をクリックします。</p><p>次に、Kitsuがショットを作成します。</p><p><img src="'+us+'" alt="EDLショット作成"></p><p>::: 詳細 CSVスプレッドシートファイルからショットを作成 ショットのリストがすでにスプレッドシートファイルで用意されているかもしれません。Kitsuでは、インポートする方法が2つあります。1つ目は、<code>.csv</code>ファイルを直接インポートする方法、2つ目は、データを直接Kitsuにコピー＆ペーストする方法です。</p><p>まず、スプレッドシートを<code>.csv</code>ファイルとして保存します。</p><p>次に、Kitsuのショットページに戻り、<strong>インポート</strong>アイコンをクリックします。 <img src="'+s+'" alt="インポートアイコン"></p><p>「CSVからデータをインポート」というポップアップウィンドウが開きます。「参照」をクリックして、<code>.csv</code>ファイルを選択します。</p><p><img src="'+bs+'" alt="CSVファイルのインポート"></p><p>結果を確認するには、「プレビュー」ボタンをクリックします。</p><p>データのプレビューで、列の名前を確認し、調整することができます。</p><p>注意：<strong>エピソード</strong>の列は、<strong>テレビ番組</strong>の制作には必須です。</p><p><img src="'+e+'" alt="インポートプレビューデータ"></p><p>すべてが適切であることを確認したら、<strong>確認</strong>ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、すべてのショットがKitsuにインポートされ、<strong>設定</strong>に従ってタスクが作成されます。</p><p><img src="'+p+'" alt="インポート結果"> :::</p><p>::: 詳細 スプレッドシートファイルをコピー/ペーストしてショットを作成 スプレッドシートを開き、データを選択してコピーします。</p><p><img src="'+m+'" alt="データのコピー"></p><p>次に、キットゥのショットページに戻り、<strong>インポート</strong>アイコンをクリックします ！<a href="../img/getting-started/import.png">インポートアイコン</a>。</p><p>ポップアップウィンドウ「<strong>CSVからデータをインポート</strong>」が開きますので、「<strong>CSVデータを貼り付け</strong>」タブをクリックします。</p><p><img src="'+c+'" alt="CSVデータを貼り付け"></p><p>以前に選択したデータを貼り付け、<strong>[プレビュー]</strong> ボタンで結果を確認できます。</p><p><img src="'+_+'" alt="プレビューデータ"></p><p>データをプレビューすることで、列の名前を確認し、調整することができます。</p><p>注：<strong>[エピソード]</strong> 列は、<strong>[テレビ番組]</strong> 制作の場合のみ必須です。</p><p><img src="'+e+'" alt="プレビューデータ"></p><p>すべてが正しく入力されていることを確認したら、<strong>確認</strong>ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、すべてのショットがKitsuにインポートされ、<strong>設定</strong>に従ってタスクが作成されます。</p><p><img src="'+p+'" alt="インポート結果"> :::</p><h3 id="ショットの詳細を確認する" tabindex="-1">ショットの詳細を確認する <a class="header-anchor" href="#ショットの詳細を確認する" aria-label="Permalink to “ショットの詳細を確認する”">​</a></h3><p>ショットの詳細を確認したい場合は、ショット名をクリックします。</p><p><img src="'+fs+'" alt="ショットの詳細"></p><p>新しいページが開き、右側にタスク、アサイン、ステータスニュースフィードの一覧が表示されます。 タブ名をクリックすることで、各タブを切り替えることができます。</p><p><img src="'+ks+'" alt="ショット詳細ページ"></p><p>各タスクのステータスをクリックすると、コメントパネルが開き、コメントの履歴や異なるバージョンを確認できます。</p><p><img src="'+Ks+'" alt="ショット詳細ページ"></p><p>また、<strong>キャスティング</strong>にもアクセスできます。</p><p><img src="'+Cs+'" alt="アセット詳細キャスティング"></p><p>タスクタイプページのデータを事前に記入している場合は、<strong>スケジュール</strong>を利用できます。データがすでに記入されている場合は、ここで直接修正できます。</p><p><img src="'+xs+'" alt="アセット詳細キャスティング"></p><p>さまざまなタスクタイプでアップロードされた<strong>プレビューファイル</strong>、</p><p><img src="'+Ps+'" alt="Asset Detail Casting"></p><p>そして、このアセットのタスクでタイムシートが記入されている場合の<strong>タイムログ</strong>。</p><p><img src="'+Ss+'" alt="Asset Detail Casting"></p><h2 id="ショットを更新する" tabindex="-1">ショットを更新する <a class="header-anchor" href="#ショットを更新する" aria-label="Permalink to “ショットを更新する”">​</a></h2><p>ショットはいつでも更新でき、名前や順序を変更したり、説明文を修正したり、グローバルページに追加したカスタム情報を追加したりすることができます。</p><p>ショットページに移動し、修正したいショットの上にカーソルを合わせてから、<strong>[編集]</strong>ボタンをクリックしてショットを編集できます ！<a href="../img/getting-started/edit_button.png">編集ボタン</a> (1) 行の右側にある。</p><p><img src="'+i+'" alt="アセットの編集"></p><p>メインショットページの説明を拡張するには、最初の文字 (2) をクリックすると、説明の全文を含むポップアップが開きます。</p><p>::: 詳細 ショット情報のCSVインポートによる更新 CSVインポート<strong>を使用して、</strong>NBフレーム<strong>、</strong>フレームIN<strong>、</strong>フレームOUT<strong>、または任意のカスタム</strong>メタデータ列**としてデータを更新することができます。</p><p>タスクの<strong>割り当て</strong>と<strong>ステータス</strong>を更新し、<strong>コメント</strong>を追加することができます。</p><p>スプレッドシートを開き、データを選択してコピーします。</p><p><img src="'+m+'" alt="インポートコピーデータ"></p><p>次に、Kitsuのショットページに戻り、<strong>インポート</strong>アイコンをクリックします <img src="'+s+'" alt="インポートアイコン">。</p><p>ポップアップウィンドウ<strong>インポートデータからCSV</strong>が開きます。<strong>CSVデータを貼り付け</strong>タブをクリックします。</p><p><img src="'+c+'" alt="インポートデータのコピー＆ペーストタブ"></p><p>以前に選択したデータをペーストし、<strong>[プレビュー]</strong>ボタンで結果を確認できます。</p><p><img src="'+_+'" alt="インポートデータのコピー＆ペーストデータ"></p><p>オプション：既存のデータを更新** をオンにする必要があります。 更新されたショットは青くなります。</p><p>注：<strong>エピソード</strong>の列は、<strong>テレビ番組</strong>制作の場合のみ必須です。</p><p><img src="'+Vs+'" alt="インポートデータのコピー＆ペースト"></p><p>すべてが適切であることを確認したら、<strong>確認</strong>ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、すべてのショットがKitsuにインポートされ、<strong>設定</strong>に従ってタスクが作成されます。</p><p><img src="'+p+'" alt="インポートデータコピーペーストデータ"> ::::</p><h2 id="ショットを作成した後にタスクを追加する" tabindex="-1">ショットを作成した後にタスクを追加する <a class="header-anchor" href="#ショットを作成した後にタスクを追加する" aria-label="Permalink to “ショットを作成した後にタスクを追加する”">​</a></h2><p>ショットを作成した後にタスクが不足していることに気づいた場合でも、追加することができます。</p><p>まず、不足しているタスクの種類がタスクの種類タブの設定ページに追加されていることを確認します（そうでなければ）。</p><p>次に、ショットのページに戻り、+タスクを追加をクリックします。</p><h2 id="ショットにフレーム番号と範囲を追加する" tabindex="-1">ショットにフレーム番号と範囲を追加する <a class="header-anchor" href="#ショットにフレーム番号と範囲を追加する" aria-label="Permalink to “ショットにフレーム番号と範囲を追加する”">​</a></h2><p>この段階では、アニマティックは完成しているはずです。つまり、各ショットの時間（フレーム数）とフレーム範囲（フレームインとフレームアウト）がわかっているはずです。この情報をスプレッドシートに入力することで、フレームの計算を正確に行うことができ、フレームの抜けや重複を防ぐことができます。</p><p>::: 警告 ショットとシーケンスを手動で作成した場合、フレーム列が非表示になっている可能性があります。 表示するには、少なくとも1つのショットを編集してフレーム数を入力する必要があります。 または、CSV/スプレッドシートでフレーム数をインポートした場合は、フレーム列が表示されます。 :::</p><p>ショットにフレーム範囲情報を追加するには、以下の手順に従います。</p><ol><li><strong>ショットの編集：</strong>ショット行の右側にある編集ボタン（<img src="'+h+'" alt="edit button">）をクリックします。</li></ol><p><img src="'+l+'" alt="edit shot Change sequence"></p><ol start="2"><li><strong>フレーム範囲の入力：</strong>編集ウィンドウでショットの開始フレームと終了フレームを入力し、確認ボタンをクリックして保存します。</li></ol><p>ショット編集ページ](../img/getting-started/shot_edit.png)</p><p>フレーム範囲がショットページの全体スプレッドシートに表示されます。</p><p>ショット編集ページ](../img/getting-started/shot_framerange_global.png)</p><ol start="3"><li><strong>フレーム情報の入力：</strong> フレーム、イン、アウトの列のロックが解除されたら、グローバルショットページから直接データを入力できます。入力したいケースをクリックしてデータを追加します。</li></ol><p>::: ヒント フレームインとフレームアウトを入力すると、Kitsuが自動的にフレーム数を計算します。 :::</p><p><img src="'+Ds+'" alt="ショット編集ページ"></p><ol start="4"><li><p><strong>CSV インポート:</strong> フレーム範囲を素早く更新するには、CSV インポートも利用できます。 <a href="#update-your-shots">CSV インポートでショット情報を更新</a></p></li><li><p><strong>ショット履歴へのアクセス:</strong> フレーム範囲を含むショット値の履歴を表示できます。</p></li></ol><p><img src="'+ws+'" alt="ショットのフレーム範囲の詳細"></p><p><img src="'+vs+'" alt="ショット値の履歴"></p><h2 id="カスタムメタデータ列の作成" tabindex="-1">カスタムメタデータ列の作成 <a class="header-anchor" href="#カスタムメタデータ列の作成" aria-label="Permalink to “カスタムメタデータ列の作成”">​</a></h2><p>一般的なスプレッドシートページに追加情報を含めるには、カスタム<strong>メタデータ列</strong>を作成する必要があります。</p><p>追加したい詳細情報として、<strong>難易度</strong>、<strong>天候</strong>、<strong>タグ</strong>などがあるかもしれません。 すべてのテキストまたは数値情報は、カスタムメタデータ列に保存することができます。</p><p>::: 警告 1つのエピソードで作成されたカスタムメタデータ列は、すべてのエピソードに適用されます。 :::</p><p>カスタムメタデータ列を作成するには、以下の手順に従います。</p><ol><li><strong>列の追加:</strong> 名前列の近くにある<strong>+</strong>をクリックします。</li></ol><p><img src="'+As+'" alt="メタデータカラム"></p><ol start="2"><li><strong>タイプを選択:</strong> タイプオプションで、情報をどのように保存するかを選択します。</li></ol><ul><li><strong>テキスト</strong></li><li><strong>数値</strong></li><li><strong>チェックボックス</strong></li><li><strong>値のリスト</strong></li><li><strong>タグのリスト</strong></li><li><strong>チェックリスト</strong></li></ul><p><img src="'+Es+'" alt="メタデータ カラム詳細"></p><p>::: 警告</p><ul><li><strong>テキスト</strong>、<strong>数値</strong>、および<strong>チェックボックス</strong>は、事前の計画なしに各エンティティに異なる情報を追加することができます。</li><li><strong>値のリスト</strong>、<strong>タグのリスト</strong>、および<strong>チェックリスト</strong>は、各エンティティに同じオプションを提供し、事前に記入する必要があります。</li></ul><p><img src="'+Ls+'" alt="メタデータ列のリスト"> 以下のリスト要素を入力します。利用可能な値をクリックして選択します。 :::</p><ol start="3"><li><strong>部門へのリンク:</strong> オプションとして、メタデータ列を1つまたは複数の部門にリンクすることができます。これにより、アーティスト/スーパーバイザーは、自分のToDoページおよび部門別にフィルタリングされたビューで表示できるようになります。</li></ol><p>::: ヒント メタデータ列を部署にリンクするには、リストから部署をクリックし、<strong>追加</strong>をクリックして適用します。</p><p>ここでは、VFX列が2つの部署にリンクされています。</p><p><img src="'+$s+'" alt="部署メタデータ列のフィルタ表示"> :::</p><p>::: 詳細 メタデータカラムの編集 アセットまたはショットのグローバルページで、メタデータカラムの右側にある矢印をクリックし、<strong>[編集]</strong> を選択します。</p><p><img src="'+Ts+'" alt="メタデータカラムの編集"> :::</p><ol start="4"><li><strong>情報の入力:</strong> グローバルスプレッドシートページで直接情報を入力できます。 ケースは編集可能です。</li></ol><p><img src="'+Bs+'" alt="メタデータカラムの詳細"></p><p>::: ヒント 左側の複数のエンティティを選択し、メタデータカラムを一括で変更することができます。 :::</p><p>::: 詳細 手動で編集 編集ボタン（<img src="'+h+'" alt="編集ボタン">）をクリックして、情報を手動で変更することもできます。</p><p>編集ポップアップに新しい行が表示され、リストから情報を選択したり、自由形式のテキストや数値を入力したり、チェックボックスにチェックを入れたり、チェックリストを使用したりすることができます。</p><p>作業が完了したら、[Confirm] ボタンをクリックしてください。</p><p><img src="'+Fs+'" alt="メタデータカラムの詳細"> :::</p><ol start="5"><li><strong>編集または削除:</strong> メタデータ列を編集または削除するには、スプレッドシートの一般ページに移動します。 メタデータ列の名前の隣にある矢印をクリックします。</li></ol><p>::: ヒント 列名の右にある矢印をクリックしてメニューを開き、「ソート」を選択することで、この新しい列でグローバルページをソートすることもできます。</p><p>また、メタデータ列を左側に固定することもできます。 :::</p><h2 id="シーケンスの作成" tabindex="-1">シーケンスの作成 <a class="header-anchor" href="#シーケンスの作成" aria-label="Permalink to “シーケンスの作成”">​</a></h2><p>Kitsuでは、<strong>シーケンス</strong>レベルでタスクを追跡することもできます。 これは、 ストーリーやカラーボード、カラーグレーディングなど、追跡するマクロタスクがある場合に特に便利です。</p><p>ナビゲーションメニューを使用して、<strong>シーケンス</strong>ページに移動します。</p><p><img src="'+Ns+'" alt="ナビゲーションシーケンス"></p><p>::: 警告 この新しいページは、アセットおよびショットのグローバルページと同様に動作します。</p><p>このページを使用するには、まず<strong>グローバルライブラリ</strong>に<strong>シーケンス</strong>属性を持つ専用のタスクタイプを作成する必要があります。</p><p><a href="./../configure-kitsu/#studio-workflow-create-a-new-task-type">新しいタスクタイプの作成方法</a>を参照してください</p><p>グローバルライブラリに<strong>タスクタイプ</strong>を作成したら、それを** プロダクションライブラリ**（設定ページ）に追加します。 :::</p><p>タスクタイプが設定ページで準備できたら、シーケンス（アセットまたはショットと同じ）を作成する必要があります。</p><p>この新しいページは、アセットやショットのグローバルページと同様に動作します。<strong>+ 新規シーケンス</strong> ボタンで編集を追加できます。</p><p>タスクの割り当て、レビュー、ステータスの変更などを行うことができます。</p><p>メタデータ列を追加したり、説明を記入したりすることができます。</p><p>::: ヒント シーケンスは、ここ（<strong>+新規シーケンス</strong>ボタン）から直接作成することも、グローバルショットページからショットにリンクされたシーケンスを作成することもできます。 :::</p><p>このページでは、アセットやショットと同様に、シーケンスのエンティティを<strong>名前変更</strong>したり、<strong>削除</strong>したりすることができます。</p><p>シーケンス名をクリックすると、そのシーケンスの詳細ページが表示されます。</p><p><img src="'+ys+'" alt="シーケンス詳細ページ"></p><p>詳細ページでは、シーケンスのキャスティングにアクセスできます。 シーケンス全体で使用されているすべてのアセットを確認できます。</p><p>また、シーケンスのスケジュール、プレビューファイル、アクティビティ、タイムログの<strong>タスク</strong>にもアクセスできます。</p><h2 id="作成と編集" tabindex="-1">作成と編集 <a class="header-anchor" href="#作成と編集" aria-label="Permalink to “作成と編集”">​</a></h2><p>Kitsuでは、<strong>編集</strong>レベルでタスクを追跡することができます。</p><p>これは、複数の検証ステップを通じて複数の編集を追跡する必要がある場合に特に便利です。例えば、映画全体、複数の予告編、ファースト・エディット、ファイン・エディット、ミックスなどを追跡することができます。</p><p>::: 警告 デフォルトでは、<strong>Edit</strong> ページは、<strong>プロダクションライブラリ</strong>（設定ページ）にそれ用のタスクタイプが作成されるまで表示されません。</p><p>[新しいタスクタイプの作成方法]（../configure-kitsu/index.md#studio-workflow-create-a-new-task-type）を参照してください。 :::</p><p>このページを使用するには、まず<strong>グローバルライブラリ</strong>で<strong>編集</strong>属性を持つ専用のタスクタイプを作成する必要があります。</p><p>グローバルライブラリ<strong>で</strong>タスクタイプ<strong>を作成したら、</strong>プロダクションライブラリ<strong>に追加します。その後、ナビゲーションのドロップダウンメニューに</strong>編集**オプションが表示されます。</p><p><img src="'+Ms+'" alt="ナビゲーション編集"></p><p>この新しいページは、アセットおよびショットのグローバルページと同様に動作します。<strong>+ 新規編集</strong>ボタンで編集を追加できます。</p><p>タスクの割り当て、レビューの実施、ステータスの変更などを行うことができます。</p><p>また、メタデータ列を追加したり、説明を記入したりすることもできます。</p><p>::: ヒント 配信内容に応じて、<strong>[編集]</strong> ごとの解像度を変更することもできます。 :::</p><p>::: 警告 詳細ページは、他のエンティティとは異なります。</p><p><strong>[編集]</strong> は特定のロングビデオに焦点を当てているため、詳細ページはコメントの詳細ページにより近いものとなっています。 :::</p><p>このページでは、アセットやショットのエンティティと同様に、<strong>[編集]</strong> エンティティの <strong>[名前の変更]</strong> や <strong>[削除]</strong> を行うことができます。</p><h2 id="ブレイクダウンリストの作成" tabindex="-1">ブレイクダウンリストの作成 <a class="header-anchor" href="#ブレイクダウンリストの作成" aria-label="Permalink to “ブレイクダウンリストの作成”">​</a></h2><p>ブレイクダウンを記入すると、ショットの組み立てに役立ちます。 ブレイクダウンには、ショットを作成するために追加する必要のあるアセットの詳細がすべて記載されています。 これにより、何も漏れなく確実に作業を進めることができます。</p><p>ドロップダウンメニューで <strong>[BREAKDOWN]</strong> を選択します。</p><p><img src="'+Rs+'" alt="drop down Menu breakdown"></p><p>ブレークダウンページの左側には、エピソード/シーケンス/ショットメニュー（1）があります。作成したものの中から選択できます。これらは画面の右側にあり、 作成したすべてのアセットは、この制作（メインパックおよびエピソード）で利用できます（3）。さらに、 中央セクションでは、ショットの選択を行います（2）。</p><p><img src="'+Gs+'" alt="ブレークダウンページ"></p><p>では、次にキャストしたいショットを選択します。</p><p>サムネイルがまだない場合はアセットをテキストで表示したり、 サムネイルのサイズを拡大することができます。</p><p><img src="'+Hs+'" alt="ブレイクダウンページのテキスト表示"></p><p>また、ブレイクダウン中にリストにアセットを追加する必要があることに気づくかもしれません。</p><p>ブレークダウンページから直接、新しいアセットを作成することができます。「利用可能なすべてのアセット」の右側にある「+」をクリックします。</p><p><img src="'+Is+'" alt="ブレークダウンページでアセットを作成"></p><p>また、複数のショットを一度に選択することもできます。最初のショットをクリックし、<strong>シフト</strong>キーを押したまま、選択する最後のショットをクリックします。</p><p><img src="'+Os+'" alt="ページのグローバル一括選択"></p><p>次に、割り当てたいアセットをクリックします。 キャラクター、背景など、右側の部分 (3) から選択します。 複数のショットを選択した場合、選択した内容は多数のショットに適用されます。</p><p>アセットが配置されたショットをコピーし、このアセット選択を別のショットに貼り付けます。</p><p>アセットの上にカーソルを移動させると、<strong>+1</strong> または <strong>+10</strong> と表示されます。これは、 そのアセットを追加した回数を表しており、必要なだけクリックできます。</p><p><img src="'+qs+'" alt="ブレークダウンでアセットを追加"></p><p>シーケンスやショットを指定せずに、すべてのアセットをテレビ番組のエピソードにリンクすることもできます。</p><p><img src="'+js+'" alt="Breakdown episode asset"></p><p>この方法では、ストーリーボード/アニマティックの段階の前に、すべてのアセットを1つまたは複数のエピソードにリンクすることができます。</p><p>画面中央にアセットが表示されているのが確認できます（2）。 アセット名の隣には、追加された回数が表示されています。この 例では、キャラクターアセット「Llama」を2回追加しています。</p><p>誤ってアセットを2回追加してしまった場合は、画面中央部分でこのショットのアセットを選択する必要があります（2）。そこから、<strong>-1</strong>をクリックします。 このショットの作業が完了したら、他のショットの作業に進みます。 選択した内容は自動的に保存されます。</p><p><img src="'+Qs+'" alt="Breakdown remove asset"></p><p>ストーリーボードの作成中に新しいアセットが作成された場合は、アセットページに戻り （ドロップダウンメニューを使用）、必要なアセットを作成します。 以前に作成されたタスクは、これらの新しいアセットに即座に適用されます。 ただし、割り当てを行う必要があり、その後、 ブレイクダウンを継続できます。</p><p>これで、<strong>Breakdown</strong>ページは以下のようになります。</p><p><img src="'+r+'" alt="breakdown add asset bulk"></p><p>アセットを組み立てて個々のパーツを追跡する必要がある場合は、アセットのブレークダウンリストを作成することもできます。</p><p>画面左上にある<strong>FOR</strong>の下のドロップダウンメニューで<strong>asset</strong>を選択します。</p><p><img src="'+Xs+'" alt="アセットのブレークダウンメニュー"></p><p>2番目のドロップダウンメニューにアクセスして、アセットの種類を選択できます。 <strong>キャラクター</strong>、<strong>環境</strong>、<strong>小道具</strong>、<strong>FX</strong>、...</p><p><img src="'+Ws+'" alt="アセットの種類ブレークダウン"></p><p>ショットの作成と同様の手順でアセットのブレークダウンページを完成させることができます。まず、左側の部分で1つまたは複数のアセットを選択し、次に右側の部分の要素を追加します。</p><p>::: 詳細 CSVファイルからブレークダウンリストを作成する</p><p>すでにスプレッドシートファイルでブレイクダウンリストが準備できているかもしれません。Kitsuでは、それをインポートする方法が2つあります。1つ目は、.csvファイルを直接インポートする方法、2つ目は、データを直接Kitsuにコピー＆ペーストする方法です。</p><p>まず、Kitsuの推奨に従って、スプレッドシートを「.csv」ファイルとして保存します。</p><p>インポート]ボタンをクリックします！[インポート]ボタン（../img/getting-started/import.png）</p><p>「CSVからデータをインポート」というポップアップウィンドウが開きます。「参照」をクリックして、<code>.csv</code>ファイルを選択します。</p><p><img src="'+d+'" alt="インポートされたCSVファイルのブレークダウン"></p><p>結果を確認するには、「プレビュー」ボタンをクリックします。</p><p>データのプレビューで、列の名前を確認し、調整することができます。</p><p>注意：<strong>エピソード</strong>の列は、<strong>テレビ番組</strong>の制作の場合のみ必須です。</p><p><img src="'+u+'" alt="Breakdown import Preview"></p><p>すべてが適切であることを確認したら、<strong>Confirm</strong>ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、ブレークダウンがKitsuにインポートされました。</p><p><img src="'+r+'" alt="内訳のインポートプレビュー"> :::</p><p>::: 詳細 スプレッドシートファイルをコピー/貼り付けして内訳リストを作成</p><p>スプレッドシートを開き、データを選択してコピーします。</p><p><img src="'+Js+'" alt="データのコピーをインポート"></p><p>次に、Kitsuのブレークダウンページに戻り、<strong>インポート</strong>アイコンをクリックします <img src="'+s+'" alt="インポートアイコン">。</p><p>ポップアップウィンドウ「<strong>CSVからデータをインポート</strong>」が開きますので、「<strong>CSVデータを貼り付け</strong>」タブをクリックします。</p><p><img src="'+d+'" alt="インポートデータのコピー＆ペーストタブ"></p><p>以前に選択したデータを貼り付け、<strong>[プレビュー]</strong> ボタンで結果を確認できます。</p><p><img src="'+u+'" alt="データのコピー＆ペースト"></p><p>データのプレビューで列の名前を確認し、調整できます。</p><p>注：<strong>[エピソード]</strong> 列は、<strong>[テレビ番組]</strong> 制作には必須です。</p><p>すべてが適切に設定されたら、<strong>Confirm</strong>（確認）ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、すべてのアセットがKitsuにインポートされました。</p><p><img src="'+r+'" alt="インポートデータ コピーペーストデータ"> :::</p><h2 id="アセットの状態の紹介-使用可能" tabindex="-1">アセットの状態の紹介：使用可能 <a class="header-anchor" href="#アセットの状態の紹介-使用可能" aria-label="Permalink to “アセットの状態の紹介：使用可能”">​</a></h2><p>ほとんどの場合、ショットタスクでアセットを使用する際に、アセットのタスクが承認されるのを待つ必要はありません。</p><p>たとえば、アセットが<strong>コンセプト</strong>段階で承認された場合、<strong>ストーリーボード</strong>段階で使用することができます。 次に、<strong>モデリング</strong>段階で承認された場合、<strong>レイアウト</strong>段階で使用することができます。</p><p>まさにアセットの状態<strong>「準備完了」</strong>がやっていることです。この状態は、アセットのタスクの状態を知らせ、ショットのタスクに対する使用可能性を比較します。</p><p>ブレークダウンを記入したので、どのショットにどのアセットが使用されているかが正確にわかります。</p><p>まず、タスクのステータスと関連するアセットの状態を定義する必要があります。セルをクリックして<strong>「準備完了」</strong>を変更することができます。ショットタスクのドロップダウンメニューが表示されます。</p><p><img src="'+Us+'" alt="アセットステータス"></p><p>::: ヒント <strong>自動化</strong>を使用して、作業の大部分を自動化することができます。</p><p><strong>準備完了</strong>トリガーで自動化を設定できます。</p><p><a href="./../configure-kitsu/#automation">ステータス自動化の作成方法</a>を参照</p><p>:::</p><p>アセットの状態をいくつか<strong>準備完了</strong>に変更したので、ショットページで結果を確認できます。</p><p>いくつかの白いボックスが<strong>緑色</strong>になっていることに気づくでしょう。このショットで使用されるすべてのアセットが、この特定のタスクの準備ができていることを意味します。</p><p><img src="'+zs+'" alt="アセットステータス"></p><p>白いボックスが表示されている場合、Kitsuは、このタスクに準備ができているアセットの数を示します。</p><p><img src="'+Ys+'" alt="アセットステータス"></p><p>::: ヒント ボックスが表示されていない場合、このショットにはアセットがキャストされていません。 :::</p><p>次に、ショット名をクリックして詳細ページに移動します。 すると、このショットで使用されているすべてのアセットとそのステータスが表示されます。</p><p><img src="'+Zs+'" alt="アセットステータス"></p><p>特定のタスクでショットを開始できるかどうかを判断する最も簡単な方法です。</p>',468)])])}const lt=b(st,[["render",tt]]);export{it as __pageData,lt as default};
